    public int numErrores = 0;

    public void syntax_error(Symbol s) {
        numErrores++;
        String token = s.value != null ? "'" + s.value + "'" : "token desconocido";
        System.err.println("Error sintáctico en línea " + s.left +
                           ", columna " + s.right +
                           ": token inesperado " + token);
    }

    public void unrecovered_syntax_error(Symbol s) {
        numErrores++;
        if (s.left == -1) {
            System.err.println("Error irrecuperable: se llegó al final del archivo sin poder recuperarse.");
        } else {
            System.err.println("Error irrecuperable en línea " + s.left +
                               ", columna " + s.right +
                               ": el análisis no puede continuar.");
        }
    }

